import{_ as l,o as r,c as t,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"G02 董監事異動 — 力成科技 (6239)","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6239_力成/20260617/G02_董監事異動.md","filePath":"審計報告庫/經營審計/6239_力成/20260617/G02_董監事異動.md"}'),o={name:"審計報告庫/經營審計/6239_力成/20260617/G02_董監事異動.md"};function i(n,a,s,h,_,d){return r(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="g02-董監事異動-—-力成科技-6239" tabindex="-1">G02 董監事異動 — 力成科技 (6239) <a class="header-anchor" href="#g02-董監事異動-—-力成科技-6239" aria-label="Permalink to &quot;G02 董監事異動 — 力成科技 (6239)&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>檢視力成科技董事與監察人（含獨立董事）的異動情況、專業背景、獨立性及對公司治理的影響。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>2026年5月股東會改選9席董事（含4席獨董），蔡篤恭續任董座，呂肇祥退休、古口榮男卸任，林基正與謝再居入列，變動幅度適中，治理穩定。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>力成2026年5月全面改選9席董事（含4席獨董，佔比44%）。林基正（技術背景）、謝再居（財務背景）新任；呂肇祥退休、古口榮男換將。金士頓維持兩席，最大股東影響力不變。整體評級優，專業多元性充足。（數據來源：鉅亨網、BigGo）</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>力成科技第11屆董事改選於2026年5月27日舉行，主要變動分析如下：</p><p><strong>一、新任董事背景</strong></p><ul><li>林基正：力成科技資深副總經理，長期主導技術研發與產線管理，加入董事會有助於技術觀點與經營決策的對接。</li><li>謝再居：新任獨立董事，具備財務/會計專業背景，補強原獨董李培瑛（南亞科前總經理）卸任後的專業空缺。</li></ul><p><strong>二、卸任原因</strong></p><ul><li>呂肇祥：2026年4月辭任總經理並退休，因此未再續任董事。其退休屬於正常世代交替。</li><li>古口榮男：金士頓投資專戶原代表人，因金士頓內部人事調整換將。</li><li>李培瑛：南亞科前總經理，因個人規劃卸任獨董。</li></ul><p><strong>三、董事會結構分析</strong></p><ul><li>非獨立董事5席：蔡篤恭（金士頓背景/董事長）、吳麗卿（金士頓代表）、謝永達（超豐董事長/力成執行長）、淺田順一（鎧俠代表）、林基正（力成內部）</li><li>獨立董事4席：張光瑤（前經濟部次長）、陳瑞聰（仁寶副董事長）、童兆勤（前中華電信董事長）、謝再居（財務背景）</li><li>獨董佔比44.4%，高於法定的1/3，且均具備產業/財務/電信等多元背景。</li></ul><p><strong>四、公司治理亮點</strong> 力成設有永續發展與風險管理委員會（2025年由風險管理委員會更名）、審計委員會、薪酬委員會等，均由獨董擔任召集人。董事會每年進行績效評估，並安排董監事責任險。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>🔴 空方觀點（利空風險）</strong></p><ol><li><strong>內部人主導風險</strong>：5席非獨董中，蔡篤恭、謝永達、林基正均為力成集團內部人或關係人，加上金士頓法人代表吳麗卿，內部關聯席次佔比高達3/5，潛在利益衝突監控需依賴獨董的獨立判斷。</li><li><strong>記憶體產業同質性偏高</strong>：獨董雖多元但主要背景集中於電子產業與政府，缺乏營運/行銷/國際法務等專業互補，對AI、光學封裝等新業務的監督視角可能不足。</li></ol><p><strong>🟢 多方觀點（機會可能性）</strong></p><ol><li><strong>治理高度合規</strong>：獨董佔比44%、設有完整功能性委員會、每年績效評估、投保董監責任險，公司治理實務領先同業，有利於外資與ESG資金的布局信心。</li><li><strong>战略股東深度綁定</strong>：金士頓近30年持股關係穩定，鎧俠（東芝記憶體）亦派法人代表，主要客戶/供應鏈直接參與董事會，降低資訊不對稱風險，有助於長單合約的維繫與產能規劃。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>web_search：力成 6239 董監事異動 2025 2026（鉅亨網、BigGo）</li><li>web_search：力成 6239 法說會（Fugle法說會備忘錄2026/04/28）</li></ul>',23)])])}const u=l(o,[["render",i]]);export{c as __pageData,u as default};
